<template>
<transition name="modal">
      <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block dialog">
          <div class="modal-dialog">
            <div class="modal-content">
              <div class="modal-header theme-primary partition-full">
                <h4 class="modal-title">{{ $t("Payment") }}</h4>
                <button type="button" class="close" v-on:click="ClosePayment">
                  <em class="fa fa-times" aria-hidden="true"></em>
                </button>
              </div>
              <div class="modal-body">
                <div class="card-body float-left p-0 col-12 float-left">
                  <div class="row">
                    <div class="col-md-4 col-lg-4">
                      <div class="form-group">
                        <label>{{ $t("BillNumber") }}:
                          {{ paymentDetailsData[0].BILL_NUMBER }}</label>
                      </div>
                    </div>

                    <div class="col-md-4 col-lg-4">
                      <div class="form-group">
                        <label>{{ $t("IssueDate") }}:
                          {{
                          formatDateM(paymentDetailsData[0].BILL_ISSUE_DATE)
                          }}</label>
                      </div>
                    </div>
                    <div class="col-md-4 col-lg-4">
                      <div class="form-group">
                        <label>{{ $t("DueDate") }}:
                          {{
                          formatDateM(paymentDetailsData[0].BILL_DUE_DATE)
                          }}</label>
                      </div>
                    </div>
                    <div class="col-md-4 col-lg-4">
                      <div class="form-group">
                        <label>Total Amount ({{ paymentDetailsData[0].ISO_CODE }}):
                          <span v-if="paymentDetailsData[0].BILL_NET_TOTAL == 0">0.00</span>
                           <span v-if="paymentDetailsData[0].BILL_NET_TOTAL != 0"> {{ $n(paymentDetailsData[0].BILL_NET_TOTAL, "currency", $getLocaleByCurrency(paymentDetailsData[0].ISO_CODE))}}</span>
                        </label>
                      </div>
                    </div>
                    <div class="col-md-4 col-lg-4">
                      <div class="form-group">
                        <label>Paid Amount Till Now ({{
                          paymentDetailsData[0].ISO_CODE
                          }}):
                            <span v-if="paymentDetailsData[0].PAID>0">{{ $n(paymentDetailsData[0].PAID, "currency", $getLocaleByCurrency(paymentDetailsData[0].ISO_CODE))}}</span>
                            <span v-else
                            >0.00</span>
                        </label>
                      </div>
                    </div>

                    <div class="col-md-4 col-lg-4">
                      <div class="form-group">
                        <label>Payment Date:</label>
                        <span> {{ paymentDate }} </span>
                      </div>
                    </div>

                    <!-- 
                                     <div class="clearfix"></div>
                                         <div class="col-lg-12">
                                        <label>Payment Date:<span class="mandatory">*</span></label>
                                       <input id="PaymentDate" class="form-control" v-model="paymentDate" readonly/>
                                     </div> -->

                    <div class="clearfix"></div>

                    <div class="listing mt-2 col-lg-12" v-if="paymentDetailsData[0].HAS_MULIPLE_TERMS">
                      <div class="table-responsive table-fix-header">
                        <table id="maintable" class="table-sorting table table-bordered my-0">
                          <thead class="thead-light">
                            <tr>
                              <th width="25%">
                                <span>{{ $t("Notes") }}</span>
                              </th>
                              <th width="20%" class="text-center">
                                <span>{{ $t("Due Date") }} </span>
                              </th>
                              <th width="20%" class="text-left">
                                <span>{{ $t("Due Amount") }} ({{
                                  paymentTermsData[0].ISO_CODE
                                  }})</span>
                              </th>
                              <th width="20%" class="text-left">
                                <span>{{ $t("Mark Payment") }}</span>
                              </th>
                              <th width="15%" class="text-center">
                                <span>{{ $t("Action") }}</span>
                              </th>
                            </tr>
                          </thead>
                          <tbody>
                            <tr v-if="
                                !paymentTermsData ||
                                paymentTermsData.length == 0
                              ">
                              <td colspan="5" class="text-center text-danger">
                                {{ $t("NoPaymentFound") }}
                              </td>
                            </tr>
                            <!-- Check if payment list is available -->
                            <tr v-else-if="
                                paymentTermsData && paymentTermsData.length > 0
                              " v-for="(
                                termsPaymentRow, index
                              ) in paymentTermsData" :key="index" class="myrow">
                              <td>
                                <span>{{ termsPaymentRow.NOTES }} </span>
                              </td>
                              <td class="text-center">
                                <span>{{ formatDateM(termsPaymentRow.DUE_ON) }}
                                </span>
                              </td>
                              <td>
                                <input class="form-control" id="txtduedamount" v-model="termsPaymentRow.DUE_AMOUNT"
                                  maxlength="12" readonly />
                              </td>
                              <td>
                                <label class="mr-2" :class="{
                                    total_disable_class_bg:
                                      termsPaymentRow.DUE_AMOUNT === 0.0
                                  }">
                                  <input type="radio" value="1" v-model="termsPaymentRow.IS_FULL_PAYMENT" :checked="
                                      termsPaymentRow.IS_FULL_PAYMENT === '1'
                                    " />
                                  Full Payment
                                </label>
                                <label :class="{
                                    total_disable_class_bg:
                                      termsPaymentRow.DUE_AMOUNT === 0.0
                                  }">
                                  <input type="radio" value="0" v-model="termsPaymentRow.IS_FULL_PAYMENT" :checked="
                                      termsPaymentRow.IS_FULL_PAYMENT === '0'
                                    " />
                                  Partial
                                </label>

                                <div v-if="termsPaymentRow.IS_FULL_PAYMENT === '0'">
                                  <input type="number" class="form-control" id="txtrecivedamount"
                                    v-model="termsPaymentRow.AMOUNT_RECEIVED" maxlength="12"
                                    @blur="checkAmountReceived(termsPaymentRow)" :class="{
                                    total_disable_class_bg:
                                      termsPaymentRow.DUE_AMOUNT === 0.0
                                  }" />
                                </div>
                              </td>
                              <td class="text-center">
                                <div class="col-lg-12">
                                  <div v-if="paymentDetailsData[0].HAS_MULIPLE_TERMS">
                                    <span id="submitField">
                                      <a id="SaveMultipleTerms" title="Save" :class="{
                                          total_disable_class_bg:
                                            termsPaymentRow.DUE_AMOUNT === 0.0,
                                        }" @click="
                                          SaveMultipleTerms(termsPaymentRow)
                                        " class="submitbtn btn btn-success" href="javascript:;"><i
                                          class="fa fa-save pr-2"></i>Save</a>
                                    </span>
                                  </div>

                                  <!-- @*<a class="btn btn-danger text-white" id="PartialPopupCancel" title="@Resources.Cancel"><i class="fa fa-close pr-2"></i>@Resources.Cancel</a>*@ -->
                                </div>
                              </td>
                            </tr>
                          </tbody>
                        </table>
                      </div>
                    </div>

                    <div class="listing mt-2 col-lg-12" v-if="!paymentDetailsData[0].HAS_MULIPLE_TERMS && IsAlreadyPaid==false">
                      <div class="table-responsive table-fix-header">
                        <table id="maintable" class="table-sorting table table-bordered my-0">
                          <thead class="thead-light">
                             <tr>
                              <th width="25%">
                               
                                 <label class="float-left">Notes:</label><span class="mandatory float-left">*</span>
                              </th>

                              <th width="15%" class="text-left">
                                <label class="float-left">Amount:</label><span class="mandatory float-left">*</span>
                              </th>

                              <th width="15%" class="text-left">
                                <label class="float-left">Refrence number:</label><span class="mandatory float-left">*</span>
                              </th>

                              <th width="15%" class="text-left">
                                <label class="float-left">Bill Date:</label><span class="mandatory float-left">*</span>
                              </th>
                               <th width="15%" class="text-left">
                                <label class="float-left">Payment Mode:</label><span class="mandatory float-left">*</span>
                              </th>

                              <th width="15%" class="text-center">
                                <span>{{ $t("Action") }}</span>
                              </th>
                            </tr>
                          </thead>
                          <tbody>
                            <!-- Check if payment list is available -->
                             <tr>
                              <td>
                                <textarea name="Notes" id="txtNotes" v-model="Notes" rows="2" cols="100"
                                  class="form-control" />
                              </td>

                              <td>
                                <span class="fullPaid"
                                  v-if="paymentDetailsData.length > 0 && (paymentDetailsData[0].BILL_NET_TOTAL || 0) - (paymentDetailsData[0].PAID || 0) <= 0">Paid</span>
                                <span v-else>
                                  <input type="number" class="form-control" id="txtamount" v-model="amount"
                                  onkeypress="return event.key !== '-' && this.value.length < 12" />
                                </span>
                              </td>
                              <td>
                               <span>
                                  <input type="text" class="form-control" id="txtamount" v-model="RefNo"
                                    maxlength="18" />
                                </span>
                              </td>
                               <td>
                              <span>{{BillDate}}</span>
                            </td>
                            <td>
                             <select class="form-control" v-model="BillMode">
                                  <option value="Cash">Cash</option>
                                  <option value="Cheque">Cheque</option>
                                   <option value="Online">Online</option>
                                   <option value="DD">DD</option>
                              </select>                   
                            </td>
                              <td class="text-center">
                                <div class="col-lg-12">
                                  <a v-if="!paymentDetailsData[0].HAS_MULIPLE_TERMS"
                                    id="MakePartialPay" title="Save" @click="SavePartialPayment"
                                    class="submitbtn btn btn-success mr-2" href="javascript:;"><i
                                      class="fa fa-save pr-2"></i>Save</a>
                                </div>
                              </td>
                            </tr>
                          </tbody>
                        </table>
                      </div>
                    </div>
                    <div class="mt-2 col-lg-12" v-if="IsAlreadyPaid==true">
                    <div class="alert alert-danger text-center" role="alert">
                     {{ $t('InvoiceAlreadyPaid') }}
                    </div>
                  </div>

                    <div class="col-lg-12 text-right mt-3">
                      <a href="javascript:;" class="btn btn-danger formbtn text-white" v-on:click="ClosePayment"><em
                          class="fa fa-close pr-2"></em>{{ $t("Cancel") }}</a>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </transition>
</template>

<script>
import DataService from "../../services/DataService";
export default {
    props: {
        PaymentData:{
            type:String
        }
    },
    data() {
        return{
            isSaving: false,
            paymentDetailsData: [],
            paymentTermsData: [],
            amount: 0,
            Notes: "", // Notes for the payment
            paymentDate: "",
            isPaySlip: false,
            BillDate: '',
            BillMode: 'Cash',
            RefNo: 0,
            IsAlreadyPaid: false
        }
    },
    created(){
      var vm = this;
        this.BillPayNow(this.PaymentData);
        vm.BillDate= vm.$options.filters.formatDate(new Date());
    },
    methods:{
        async BillPayNow(item) {
            //debugger;
            var vm = this;
            vm.paymentTermsData = [];
            var invoiceId = item.BILL_ID;
            var params = `invoiceId=${invoiceId}`;
            await DataService.GetInvoicePartailPaymentDetails(params).then(function (response) {
                //debugger;
                if (response.data) {
                vm.paymentDetailsData = response.data;
                $.each(vm.paymentDetailsData, function (index, value) {
                    var paymentTerm = {
                    BILL_ID: value.BILL_ID,
                    BILL_NUMBER: value.BILL_NUMBER,
                    BILL_ISSUE_DATE: value.BILL_ISSUE_DATE,
                    BILL_DUE_DATE: value.BILL_DUE_DATE,
                    BILL_NET_TOTAL: value.BILL_NET_TOTAL,
                    PAID: value.PAID,
                    ISO_CODE: value.ISO_CODE,
                    HAS_MULIPLE_TERMS: value.HAS_MULIPLE_TERMS,
                    TERM_ID: value.TERM_ID,
                    DUE_ON: value.DUE_ON,
                    DUE_AMOUNT: value.DUE_AMOUNT,
                    NOTES: value.NOTES,
                    IS_FULL_PAYMENT: value.IS_FULL_PAYMENT == 1 ? "1" : "0", // Default value
                    AMOUNT_RECEIVED: 0.00,
                    AMOUNT_RECEIVED_OLD : value.AMOUNT_RECIEVED,
                    };
                    vm.paymentTermsData.push(paymentTerm);
                });
                //debugger;
                const currentDate = new Date();

                const day = String(currentDate.getDate()).padStart(2, "0"); // Ensure day has two digits
                const month = String(currentDate.getMonth() + 1).padStart(2, "0"); // Add 1 to month since it's 0-indexed
                const year = currentDate.getFullYear();
                vm.paymentDate = `${day}-${month}-${year}`;
                  vm.IsAlreadyPaid=false;
                  let billNetTotal = parseFloat(typeof vm.paymentDetailsData[0].BILL_NET_TOTAL === "string" ? vm.paymentDetailsData[0].BILL_NET_TOTAL.replace(/,/g, ""): vm.paymentDetailsData[0].BILL_NET_TOTAL || 0);
                  let paid = parseFloat(vm.paymentDetailsData[0].PAID || 0);
                  if ((billNetTotal - paid) == 0) {
                    vm.IsAlreadyPaid=true;
                    // vm.ShowAlert(vm.$t('InvoiceAlreadyPaid'),"warning", true, vm.$t("Alert"));
                  }
                } else {
                vm.paymentDetailsData = [];
                }
            });
        },
        formatDateM(dateTimeString) {
            if (!dateTimeString) return "";
            // Parse the input ISO date string into a JavaScript Date object
            const date = new Date(dateTimeString);

            // Define month abbreviations
            const months = [
                "Jan",
                "Feb",
                "Mar",
                "Apr",
                "May",
                "Jun",
                "Jul",
                "Aug",
                "Sep",
                "Oct",
                "Nov",
                "Dec",
            ];

            // Get the month abbreviation, day, and year
            const formattedMonth = months[date.getMonth()]; // 0-based index
            const formattedDay = date.getDate(); // Day without leading zero
            const formattedYear = date.getFullYear(); // Full year

            // Return the formatted date
            return `${formattedMonth}-${formattedDay}-${formattedYear}`;
        },
       
        ClosePayment: function () {
            var vm = this;
            vm.$parent.isPayment = false;
            vm.paymentDetailsData=[];
            vm.paymentTermsData=[];
        },
        SaveMultipleTerms(termsPaymentRow) {
      var vm = this;
      console.log('IS_FULL_PAYMENT :',termsPaymentRow.IS_FULL_PAYMENT)
      if (termsPaymentRow.IS_FULL_PAYMENT == "1") {
        console.log("PaymentOption1:", termsPaymentRow.IS_FULL_PAYMENT);
        if(parseFloat(termsPaymentRow.DUE_AMOUNT) ==parseFloat(termsPaymentRow.AMOUNT_RECEIVED_OLD))
        {
          console.log("AMOUNT_RECEIVED :",termsPaymentRow.AMOUNT_RECEIVED_OLD)
          termsPaymentRow.AMOUNT_RECEIVED = parseFloat(
          (
            Math.abs(termsPaymentRow.AMOUNT_RECEIVED_OLD + parseFloat(termsPaymentRow.DUE_AMOUNT))
          ).toFixed(2)
        );
        termsPaymentRow.DUE_AMOUNT = 0.00;
        
        }
        else
        {
        termsPaymentRow.AMOUNT_RECEIVED = termsPaymentRow.DUE_AMOUNT;
        termsPaymentRow.DUE_AMOUNT = 0.00;
        }
      } else {
        console.log("PaymentOption2:", termsPaymentRow.IS_FULL_PAYMENT);
      
        if(parseFloat(termsPaymentRow.DUE_AMOUNT) ==parseFloat(termsPaymentRow.AMOUNT_RECEIVED))
        {
          termsPaymentRow.AMOUNT_RECEIVED = parseFloat(
          (
            Math.abs(termsPaymentRow.AMOUNT_RECEIVED_OLD + parseFloat(termsPaymentRow.AMOUNT_RECEIVED))
          ).toFixed(2)
        );
          termsPaymentRow.DUE_AMOUNT = 0.00;
        }
        else if(parseFloat(termsPaymentRow.AMOUNT_RECEIVED)> parseFloat(termsPaymentRow.DUE_AMOUNT))
        {
          vm.ShowAlert(vm.$t("AmountNotGreaterThanDue"), "warning");
          return
        }
        else if (parseFloat(termsPaymentRow.AMOUNT_RECEIVED)<=0){
          vm.ShowAlert(vm.$t("AmountGreaterThenZero"), "warning");
          return
        }
        else
        {
      termsPaymentRow.AMOUNT_RECEIVED = parseFloat(
          (
            Math.abs(termsPaymentRow.AMOUNT_RECEIVED_OLD + parseFloat(termsPaymentRow.AMOUNT_RECEIVED))
          ).toFixed(2)
        );
        termsPaymentRow.DUE_AMOUNT = parseFloat(
          (
            Math.abs(termsPaymentRow.AMOUNT_RECEIVED - termsPaymentRow.DUE_AMOUNT)
             
          ).toFixed(2)
        );
        }
      }

      if (
        termsPaymentRow.AMOUNT_RECEIVED != "" &&
        termsPaymentRow.AMOUNT_RECEIVED != "0" &&
        parseFloat(termsPaymentRow.AMOUNT_RECEIVED) != 0
      ) {
        // Validate amount

        // Prepare data for the AJAX request
        const obj = {
          INVOICEID: termsPaymentRow.BILL_ID,
          AMOUNT: 0,
          DATETIME: vm.paymentDate,
          NOTES: vm.Notes,
          HAS_MULIPLE_TERMS: termsPaymentRow.HAS_MULIPLE_TERMS,
          TERM_ID: termsPaymentRow.TERM_ID,
          IS_FULL_PAYMENT:
            termsPaymentRow.IS_FULL_PAYMENT == "1" ? true : false,
          AMOUNT_RECEIVED: termsPaymentRow.AMOUNT_RECEIVED,
          DUE_AMOUNT: termsPaymentRow.DUE_AMOUNT,
        };
        console.log(obj);
        // Make the AJAX call (using axios)
        //debugger;
        DataService.SaveInvoicePartialPayment(obj).then(function (response) {
          if (response.data.Status == "Success") {
            vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t("Payment")]), "success", true, vm.$t("Alert"));
            // vm.ShowAlert(vm.$t("Payment saved successfully"), "success");
             vm.FetchData();
            vm.isPayment = false;
          } else {
            vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), "warning");
          }
        });
      } else {
        vm.ShowAlert(vm.$t("AmountNotValid"), "warning");
      }
    },
    async validateReceiptNumber(receiptNumber) {
    const receiptRegex = /^[A-Za-z0-9]{6,}$/;
    if (receiptRegex.test(receiptNumber)) {
        return true;
    } else {
        return false;
    }
    },
    async SavePartialPayment() {
      var vm = this;
      // 🔐 Prevent multiple clicks
      if (vm.isSaving) return;
      vm.isSaving = true;

      try {
        var amountToPay = vm.paymentDetailsData[0].BILL_NET_TOTAL == null ? 0 : parseFloat(
          vm.paymentDetailsData[0].BILL_NET_TOTAL
        ).toFixed(2);

        const previousPaidAmount = vm.paymentDetailsData[0].PAID == null ? 0 : parseFloat(
          vm.paymentDetailsData[0].PAID
        ).toFixed(2);

        var nowPaying = parseFloat(vm.amount) + parseFloat(previousPaidAmount);
        var result = amountToPay - nowPaying;

        if (result.toFixed(2) < 0) {
          vm.ShowAlert(vm.$t("AmountNotMoreThanTotal"), "warning");
          vm.amount = 0;
          vm.isSaving = false; // 🔄 re-enable
          return;
        }

        var validateReceiptNumber = await vm.validateReceiptNumber(vm.RefNo);
        if (!validateReceiptNumber) {
          vm.ShowAlert(vm.$t("InvalidReceiptNumber"), "warning");
          vm.isSaving = false; // 🔄 re-enable
          return;
        }

        if (!this.Notes) {
          vm.ShowAlert(vm.$t("NotesRequired"), "warning");
          vm.isSaving = false; // 🔄 re-enable
          return;
        }

        if (vm.amount != "" && vm.amount != "0" && parseFloat(vm.amount) != 0) {
          const obj = {
            INVOICEID: vm.paymentDetailsData[0].BILL_ID,
            AMOUNT: vm.amount,
            DATETIME: vm.paymentDate,
            NOTES: vm.Notes,
            HAS_MULIPLE_TERMS: vm.paymentDetailsData[0].HAS_MULIPLE_TERMS,
            AMOUNT_RECEIVED: vm.amountRecieved,
            ReferenceNumber: vm.RefNo,
            PaymentMode: vm.BillMode
          };

          const response = await DataService.SaveInvoicePartialPayment(obj);
          if (response.data.Status == "Success") {
            vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t("Payment")]), "success", true, vm.$t("Alert"));
            
            vm.amount = 0;
            vm.Notes = '';
            vm.RefNo = '';
            vm.BillMode = 'Cash';

            vm.FetchData();
            vm.isPayment = false;
          } else {
            vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), "warning");
          }
        } else {
          vm.ShowAlert(vm.$t("AmountNotValid"), "warning");
        }
      } finally {
        vm.isSaving = false;  // 🔄 ALWAYS re-enable button
      }
    }
    // async SavePartialPayment() {
    //   var vm = this;
    //   var amountToPay = vm.paymentDetailsData[0].BILL_NET_TOTAL==null?0:parseFloat(
    //     vm.paymentDetailsData[0].BILL_NET_TOTAL
    //   ).toFixed(2);
    //   const previousPaidAmount = vm.paymentDetailsData[0].PAID==null?0:parseFloat(
