    //   if (result.toFixed(2) < 0) {
    //     vm.ShowAlert(
    //       vm.$t("AmountNotMoreThanTotal"),
    //       "warning"
    //     );
    //     vm.amount = 0;
    //     return;
    //   }
    //   var validateReceiptNumber = await vm.validateReceiptNumber(vm.RefNo);
    //   if(!validateReceiptNumber){
    //     vm.ShowAlert(vm.$t("InvalidReceiptNumber"), "warning");
    //     return;
    //   }
    //   if (!this.Notes) {
    //     vm.ShowAlert(vm.$t("NotesRequired"), "warning");
    //     return;
    //   }
    //   if (vm.amount != "" && vm.amount != "0" && parseFloat(vm.amount) != 0) {
    //     const obj = {
    //       INVOICEID: vm.paymentDetailsData[0].BILL_ID,
    //       AMOUNT: vm.amount,
    //       DATETIME: vm.paymentDate,
    //       NOTES: vm.Notes,
    //       HAS_MULIPLE_TERMS: vm.paymentDetailsData[0].HAS_MULIPLE_TERMS,
    //       AMOUNT_RECEIVED: vm.amountRecieved,
    //       ReferenceNumber: vm.RefNo,
    //       PaymentMode: vm.BillMode
    //     };

    //     DataService.SaveInvoicePartialPayment(obj).then(function (response) {
    //       if (response.data.Status == "Success") {
    //         vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t("Payment")]), "success", true, vm.$t("Alert"));
    //         // vm.ShowAlert(vm.$t("Payment saved successfully"), "success");
    //         vm.amount=0;
    //         vm.Notes='';
    //         vm.RefNo='';
    //         vm.BillMode='Cash';
    //         vm.$parent.FetchData();
    //         vm.$parent.isPayment = false;
    //       } else {
    //         vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), "warning");
